    /// <summary>Get the opcode for a packet body type.</summary>
    public static ushort GetOpcode<T>() where T : IFiestaPacketBody
        => TypeToOpcode.TryGetValue(typeof(T), out var opcode)
            ? opcode
            : throw new InvalidOperationException($"No opcode registered for {typeof(T).Name}");

    /// <summary>Get the opcode for a packet body type.</summary>
    public static ushort GetOpcode(Type type)
        => TypeToOpcode.TryGetValue(type, out var opcode)
            ? opcode
            : throw new InvalidOperationException($"No opcode registered for {type.Name}");

    /// <summary>Get the packet body type for an opcode.</summary>
    public static Type? GetType(ushort opcode)
        => OpcodeToType.GetValueOrDefault(opcode);

    /// <summary>Try to get the opcode for a packet body type.</summary>
    public static bool TryGetOpcode<T>(out ushort opcode) where T : IFiestaPacketBody
        => TypeToOpcode.TryGetValue(typeof(T), out opcode);

    /// <summary>Try to get the packet body type for an opcode.</summary>
    public static bool TryGetType(ushort opcode, out Type? type)
    {
        var found = OpcodeToType.TryGetValue(opcode, out type);
        return found;
    }
